#include <bits/stdc++.h>
using namespace std;
const int N=500010;
struct node
{
	int id,num;
} a[N];
int n,m,tr[N];
bool fun2(node x,node y)
{
	if(x.num==y.num) return x.id>y.id;
	return x.num>y.num; 
}
long long ans;
long long fun(int x)
{
	long long sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=tr[i];
	return sum;
}
void add(int x,int k)
{
	for(int i=x;i<=N;i+=(i&(-i))) tr[i]+=k;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) a[i].id=i,cin>>a[i].num;
	sort(a+1,a+1+n,fun2);
	for(int i=1;i<=n;i++)
	{
		ans+=fun(a[i].id);
		add(a[i].id,1);
	}
	cout<<ans;
	return 0;
}
